// ============================================================================
// Transition functions (from qedspec operations — effects + guards)
//
// Each returns true if the guard passes and the transition fires,
// false if the guard rejects the operation.
// ============================================================================

fn initialize(s: &mut State, accounts: &InitializeAccounts) -> bool {
    if s.status != Status::Uninitialized {
        return false;
    }
    s.admin_key = accounts.admin.pubkey;
    s.pool_balance = 0;
    s.user_balance = 0;
    s.status = Status::Active;
    true
}

fn unbound_transfer(s: &mut State, accounts: &UnboundTransferAccounts, amount: u64) -> bool {
    if !((pubkey_eq(&accounts.admin.pubkey, &s.admin_key)) && (amount > 0)) {
        return false;
    }
    if s.status != Status::Active {
        return false;
    }
    s.status = Status::Active;
    true
}

fn bound_transfer(s: &mut State, accounts: &BoundTransferAccounts, amount: u64) -> bool {
    if !((pubkey_eq(&accounts.admin.pubkey, &s.admin_key)) && (amount > 0)) {
        return false;
    }
    if s.status != Status::Active {
        return false;
    }
    match s.pool_balance.checked_sub(amount) {
        Some(__v) => s.pool_balance = __v,
        None => return false,
    }
    match s.user_balance.checked_add(amount) {
        Some(__v) => s.user_balance = __v,
        None => return false,
    }
    s.status = Status::Active;
    true
}

fn stable_swap_large_guard(s: &mut State, accounts: &StableSwapLargeGuardAccounts, amount_in: u128, min_out: u128, fee_bps: u128, lane: u8, input_mint: [u8; 32], output_mint: [u8; 32]) -> bool {
    if !(pubkey_eq(&accounts.admin.pubkey, &s.admin_key)) {
        return false;
    }
    if amount_in <= 0 {
        return false;
    }
    if min_out <= 0 {
        return false;
    }
    if fee_bps > 10000 {
        return false;
    }
    if lane >= 32 {
        return false;
    }
    if !(pubkey_ne(&input_mint, &output_mint)) {
        return false;
    }
    if !(((pubkey_eq(&input_mint, &output_mint)) || (amount_in >= min_out))) {
        return false;
    }
    if mul_bps_floor_u128(amount_in, fee_bps) > amount_in {
        return false;
    }
    if amount_in < min_out {
        return false;
    }
    if amount_in > 1000000000000000 {
        return false;
    }
    if s.status != Status::Active {
        return false;
    }
    s.status = Status::Active;
    true
}

